```aether:utils/token.ts
import { randomBytes } from 'crypto';

/**
 * Generates a secure, random token.
 * @param length The length of the token in bytes (default 32 bytes, resulting in 64 hex characters).
 * @returns A hexadecimal string representation of the token.
 */
export function generateSecureToken(length: number = 32): string {
  return randomBytes(length).toString('hex');
}

/**
 * Generates an expiration date for a token.
 * @param expiresInMinutes The number of minutes until the token expires (default 60 minutes).
 * @returns A Date object representing the expiration time.
 */
export function generateExpirationDate(expiresInMinutes: number = 60): Date {
  const date = new Date();
  date.setMinutes(date.getMinutes() + expiresInMinutes);
  return date;
}
