```aether:services/user.ts
import { User, PasswordResetToken } from '../types';

// --- Mock Database ---
const users: User[] = [
  { id: 'user-1', email: 'test@example.com' },
  { id: 'user-2', email: 'another@example.com' },
];

const passwordResetTokens: Map<string, PasswordResetToken> = new Map();
// --- End Mock Database ---

export const userService = {
  /**
   * Finds a user by their email address.
   * @param email The email address to search for.
   * @returns The User object if found, otherwise undefined.
   */
  findUserByEmail(email: string): User | undefined {
    return users.find(user => user.email === email);
  },

  /**
   * Stores a password reset token for a given user.
   * @param userId The ID of the user.
   * @param token The generated reset token.
   * @param expiresAt The expiration date of the token.
   */
  storePasswordResetToken(userId: string, token: string, expiresAt: Date): void {
    passwordResetTokens.set(token, { token, userId, expiresAt });
    console.log(`[UserService] Stored reset token for user ${userId}: ${token}`);
  },

  /**
   * Retrieves a password reset token.
   * @param token The token string to retrieve.
   * @returns The PasswordResetToken object if found and not expired, otherwise undefined.
   */
  getPasswordResetToken(token: string): PasswordResetToken | undefined {
    const resetToken = passwordResetTokens.get(token);
    if (resetToken && resetToken.expiresAt > new Date()) {
      return resetToken;
    }
    // Optionally, clean up expired tokens here
    if (resetToken && resetToken.expiresAt <= new Date()) {
      passwordResetTokens.delete(token);
      console.log(`[UserService] Deleted expired token: ${token}`);
    }
    return undefined;
  },

  /**
   * Deletes a password reset token.
   * @param token The token string to delete.
   */
  deletePasswordResetToken(token: string): void {
    passwordResetTokens.delete(token);
    console.log(`[UserService] Deleted used token: ${token}`);
  },
};
```

